class Solution:
    def generate(self, n: int) -> list[list[int]]:
        out: list[list[int]] = []
        for r in range(n):
            row = [1] * (r + 1)      # 每行首尾都是 1
            for c in range(1, r):    # 中间元素 = 上一行相邻两数之和
                row[c] = out[r - 1][c - 1] + out[r - 1][c]
            out.append(row)
        return out
